            db.add(history)
            db.commit()
        except SQLAlchemyError:
            db.rollback()
            raise HTTPException(
                status_code=status.HTTP_500_INTERNAL_SERVER_ERROR,
                detail="Failed to update service order status",
            )

        return ServiceOrderService.get_by_id_or_404(db, order.id)

